MixxxMIDIPreset.controller:
/****************************************************************************************************/ // Global controls — MIDI Channel 1 (0x90 / 0xB0) /****************************************************************************************************/
// Browse encoder push (toggle focus: sidebar / track list)
[Library] MoveFocus Browse encoder push 0x90 0x00
/****************************************************************************************************/ // Note controls — MIDI Channel 2 (0x91 Deck A) /****************************************************************************************************/
// Play
[Channel1] play Play button Deck A 0x91 0x07
// CUE
[Channel1] cue_default Cue button Deck A 0x91 0x06
// Sync
[Channel1] sync_enabled Sync button Deck A 0x91 0x05
// Shift
[Channel1] DJCMIXULTRA.shiftButton Shift button Deck A 0x91 0x04
// PFL (headphone cue)
[Channel1] pfl PFL button Deck A 0x91 0x0C
// Load
[Channel1] LoadSelectedTrack Load button Deck A 0x91 0x0D
// Jog wheel touch
[Channel1] DJCMIXULTRA.wheelTouch Jog Wheel Touch Deck A 0x91 0x08
/****************************************************************************************************/ // Note controls — MIDI Channel 3 (0x92 Deck B) /****************************************************************************************************/
// Play
[Channel2] play Play button Deck B 0x92 0x07
// CUE
[Channel2] cue_default Cue button Deck B 0x92 0x06
// Sync
[Channel2] sync_enabled Sync button Deck B 0x92 0x05
// Shift
[Channel2] DJCMIXULTRA.shiftButton Shift button Deck B 0x92 0x04
// PFL (headphone cue)
[Channel2] pfl PFL button Deck B 0x92 0x0C
// Load
[Channel2] LoadSelectedTrack Load button Deck B 0x92 0x0D
// Jog wheel touch
[Channel2] DJCMIXULTRA.wheelTouch Jog Wheel Touch Deck B 0x92 0x08
/****************************************************************************************************/ // Shifted note controls — Deck A (0x94, channel 5) // The Ultra sends shifted button presses on channel+3 (same as stock MIX) /****************************************************************************************************/
// SHIFT + Play: Play Stutter
[Channel1] play_stutter SHIFT + Play Deck A 0x94 0x07
// SHIFT + CUE: Rewind to beginning
[Channel1] start SHIFT + Cue Deck A 0x94 0x06
// SHIFT + Sync: Sync Master
[Channel1] sync_leader SHIFT + Sync Deck A 0x94 0x05
// SHIFT + PFL: CUE Master
[Master] DJCMIXULTRA.cueMaster SHIFT + PFL: CUE Master 0x94 0x0C
// SHIFT + Jog wheel touch
[Channel1] DJCMIXULTRA.wheelTouchShift Jog Wheel Shift Touch Deck A 0x94 0x08
/****************************************************************************************************/ // Shifted note controls — Deck B (0x95, channel 6) /****************************************************************************************************/
// SHIFT + Play: Play Stutter
[Channel2] play_stutter SHIFT + Play Deck B 0x95 0x07
// SHIFT + CUE: Rewind to beginning
[Channel2] start SHIFT + Cue Deck B 0x95 0x06
// SHIFT + Sync: Sync Master
[Channel2] sync_leader SHIFT + Sync Deck B 0x95 0x05
// SHIFT + PFL: CUE Mix (headSplit toggle)
[Master] DJCMIXULTRA.cueMix SHIFT + PFL: Headphone CUE+MIX 0x95 0x0C
// SHIFT + Jog wheel touch
[Channel2] DJCMIXULTRA.wheelTouchShift Jog Wheel Shift Touch Deck B 0x95 0x08
/****************************************************************************************************/ // Pads — Deck A (0x96, channel 7) // Ultra has 8 pads (0x00-0x07), shifted pads at 0x08-0x0F /****************************************************************************************************/
// Hot Cues 1-8 (SET)
[Channel1] hotcue_1_activate Pad 1 Deck A 0x96 0x00
[Channel1] hotcue_2_activate Pad 2 Deck A 0x96 0x01
[Channel1] hotcue_3_activate Pad 3 Deck A 0x96 0x02
[Channel1] hotcue_4_activate Pad 4 Deck A 0x96 0x03
[Channel1] hotcue_5_activate Pad 5 Deck A 0x96 0x04
[Channel1] hotcue_6_activate Pad 6 Deck A 0x96 0x05
[Channel1] hotcue_7_activate Pad 7 Deck A 0x96 0x06
[Channel1] hotcue_8_activate Pad 8 Deck A 0x96 0x07
// Hot Cues 1-8 (SHIFT = clear)
[Channel1] hotcue_1_clear SHIFT Pad 1 Deck A 0x96 0x08
[Channel1] hotcue_2_clear SHIFT Pad 2 Deck A 0x96 0x09
[Channel1] hotcue_3_clear SHIFT Pad 3 Deck A 0x96 0x0A
[Channel1] hotcue_4_clear SHIFT Pad 4 Deck A 0x96 0x0B
[Channel1] hotcue_5_clear SHIFT Pad 5 Deck A 0x96 0x0C
[Channel1] hotcue_6_clear SHIFT Pad 6 Deck A 0x96 0x0D
[Channel1] hotcue_7_clear SHIFT Pad 7 Deck A 0x96 0x0E
[Channel1] hotcue_8_clear SHIFT Pad 8 Deck A 0x96 0x0F
// Loop pads (Deck A) — beatloop 1/2/4/8/16/32/0.5/0.25
[Channel1] beatloop_1_toggle Loop 1 Beat Deck A 0x96 0x30
[Channel1] beatloop_2_toggle Loop 2 Beat Deck A 0x96 0x31
[Channel1] beatloop_4_toggle Loop 4 Beat Deck A 0x96 0x32
[Channel1] beatloop_8_toggle Loop 8 Beat Deck A 0x96 0x33
[Channel1] beatloop_16_toggle Loop 16 Beat Deck A 0x96 0x34
[Channel1] beatloop_32_toggle Loop 32 Beat Deck A 0x96 0x35
[Channel1] beatloop_0.5_toggle Loop 0.5 Beat Deck A 0x96 0x36
[Channel1] beatloop_0.25_toggle Loop 0.25 Beat Deck A 0x96 0x37
// FX pads (Deck A)
[EffectRack1_EffectUnit1_Effect1] enabled FX1 Deck A 0x96 0x20
[EffectRack1_EffectUnit1_Effect2] enabled FX2 Deck A 0x96 0x21
[EffectRack1_EffectUnit1_Effect3] enabled FX3 Deck A 0x96 0x22
[EffectRack1_EffectUnit1] group_[Channel1]_enable FX Unit 1 enable Deck A 0x96 0x23
// FX shift pads (Deck A) — effect selector
[EffectRack1_EffectUnit1_Effect1] effect_selector SHIFT FX1 Deck A 0x96 0x28
[EffectRack1_EffectUnit1_Effect2] effect_selector SHIFT FX2 Deck A 0x96 0x29
[EffectRack1_EffectUnit1_Effect3] effect_selector SHIFT FX3 Deck A 0x96 0x2A
// Sampler pads (Deck A)
[Sampler1] cue_gotoandplay Sampler 1 Deck A 0x96 0x10
[Sampler2] cue_gotoandplay Sampler 2 Deck A 0x96 0x11
[Sampler3] cue_gotoandplay Sampler 3 Deck A 0x96 0x12
[Sampler4] cue_gotoandplay Sampler 4 Deck A 0x96 0x13
/****************************************************************************************************/ // Pads — Deck B (0x97, channel 8) /****************************************************************************************************/
// Hot Cues 1-8 (SET)
[Channel2] hotcue_1_activate Pad 1 Deck B 0x97 0x00
[Channel2] hotcue_2_activate Pad 2 Deck B 0x97 0x01
[Channel2] hotcue_3_activate Pad 3 Deck B 0x97 0x02
[Channel2] hotcue_4_activate Pad 4 Deck B 0x97 0x03
[Channel2] hotcue_5_activate Pad 5 Deck B 0x97 0x04
[Channel2] hotcue_6_activate Pad 6 Deck B 0x97 0x05
[Channel2] hotcue_7_activate Pad 7 Deck B 0x97 0x06
[Channel2] hotcue_8_activate Pad 8 Deck B 0x97 0x07
// Hot Cues 1-8 (SHIFT = clear)
[Channel2] hotcue_1_clear SHIFT Pad 1 Deck B 0x97 0x08
[Channel2] hotcue_2_clear SHIFT Pad 2 Deck B 0x97 0x09
[Channel2] hotcue_3_clear SHIFT Pad 3 Deck B 0x97 0x0A
[Channel2] hotcue_4_clear SHIFT Pad 4 Deck B 0x97 0x0B
[Channel2] hotcue_5_clear SHIFT Pad 5 Deck B 0x97 0x0C
[Channel2] hotcue_6_clear SHIFT Pad 6 Deck B 0x97 0x0D
[Channel2] hotcue_7_clear SHIFT Pad 7 Deck B 0x97 0x0E
[Channel2] hotcue_8_clear SHIFT Pad 8 Deck B 0x97 0x0F
// Loop pads (Deck B)
[Channel2] beatloop_1_toggle Loop 1 Beat Deck B 0x97 0x30
[Channel2] beatloop_2_toggle Loop 2 Beat Deck B 0x97 0x31
[Channel2] beatloop_4_toggle Loop 4 Beat Deck B 0x97 0x32
[Channel2] beatloop_8_toggle Loop 8 Beat Deck B 0x97 0x33
[Channel2] beatloop_16_toggle Loop 16 Beat Deck B 0x97 0x34
[Channel2] beatloop_32_toggle Loop 32 Beat Deck B 0x97 0x35
[Channel2] beatloop_0.5_toggle Loop 0.5 Beat Deck B 0x97 0x36
[Channel2] beatloop_0.25_toggle Loop 0.25 Beat Deck B 0x97 0x37
// FX pads (Deck B)
[EffectRack1_EffectUnit2_Effect1] enabled FX1 Deck B 0x97 0x20
[EffectRack1_EffectUnit2_Effect2] enabled FX2 Deck B 0x97 0x21
[EffectRack1_EffectUnit2_Effect3] enabled FX3 Deck B 0x97 0x22
[EffectRack1_EffectUnit2] group_[Channel2]_enable FX Unit 2 enable Deck B 0x97 0x23
// FX shift pads (Deck B)
[EffectRack1_EffectUnit2_Effect1] effect_selector SHIFT FX1 Deck B 0x97 0x28
[EffectRack1_EffectUnit2_Effect2] effect_selector SHIFT FX2 Deck B 0x97 0x29
[EffectRack1_EffectUnit2_Effect3] effect_selector SHIFT FX3 Deck B 0x97 0x2A
// Sampler pads (Deck B)
[Sampler5] cue_gotoandplay Sampler 5 Deck B 0x97 0x10
[Sampler6] cue_gotoandplay Sampler 6 Deck B 0x97 0x11
[Sampler7] cue_gotoandplay Sampler 7 Deck B 0x97 0x12
[Sampler8] cue_gotoandplay Sampler 8 Deck B 0x97 0x13
/****************************************************************************************************/ // CC controls — Global (0xB0, channel 1) /****************************************************************************************************/
// Crossfader
[Master] crossfader Crossfader 0xB0 0x00
// Browse encoder (scroll library)
[Library] MoveVertical Browse encoder 0xB0 0x01
// Master Volume
[Master] gain Master Volume 0xB0 0x03
/****************************************************************************************************/ // CC controls — Deck A (0xB1, channel 2) /****************************************************************************************************/
// Volume
[Channel1] volume Volume Deck A 0xB1 0x00
// Filter
[QuickEffectRack1_[Channel1]] super1 Filter Deck A 0xB1 0x01
// EQ Low
[EqualizerRack1_[Channel1]_Effect1] parameter1 EQ Low Deck A 0xB1 0x02
// EQ Mid
[EqualizerRack1_[Channel1]_Effect1] parameter2 EQ Mid Deck A 0xB1 0x03
// EQ High
[EqualizerRack1_[Channel1]_Effect1] parameter3 EQ High Deck A 0xB1 0x04
// Pitch slider (14-bit)
[Channel1] rate Pitch slider Deck A (MSB) 0xB1 0x08
[Channel1] rate Pitch slider Deck A (LSB) 0xB1 0x28
// Jog wheel
[Channel1] DJCMIXULTRA.scratchWheel Jog Wheel Scratch Deck A 0xB1 0x0A
[Channel1] DJCMIXULTRA.scratchWheelShift Jog Wheel Seek Deck A (Shift) 0xB4 0x0A
[Channel1] DJCMIXULTRA.bendWheel Jog Wheel Pitch Bend Deck A 0xB1 0x09
/****************************************************************************************************/ // CC controls — Deck B (0xB2, channel 3) /****************************************************************************************************/
// Volume
[Channel2] volume Volume Deck B 0xB2 0x00
// Filter
[QuickEffectRack1_[Channel2]] super1 Filter Deck B 0xB2 0x01
// EQ Low
[EqualizerRack1_[Channel2]_Effect1] parameter1 EQ Low Deck B 0xB2 0x02
// EQ Mid
[EqualizerRack1_[Channel2]_Effect1] parameter2 EQ Mid Deck B 0xB2 0x03
// EQ High
[EqualizerRack1_[Channel2]_Effect1] parameter3 EQ High Deck B 0xB2 0x04
// Pitch slider (14-bit)
[Channel2] rate Pitch slider Deck B (MSB) 0xB2 0x08
[Channel2] rate Pitch slider Deck B (LSB) 0xB2 0x28
// Jog wheel
[Channel2] DJCMIXULTRA.scratchWheel Jog Wheel Scratch Deck B 0xB2 0x0A
[Channel2] DJCMIXULTRA.scratchWheelShift Jog Wheel Seek Deck B (Shift) 0xB5 0x0A
[Channel2] DJCMIXULTRA.bendWheel Jog Wheel Pitch Bend Deck B 0xB2 0x09
/****************************************************************************************************/ // LED outputs /****************************************************************************************************/
// Transport LEDs — Deck A
[Channel1] play_indicator Play LED Deck A 0.5 1 0x91 0x07 0x7f 0x0
[Channel1] cue_indicator Cue LED Deck A 0.5 1 0x91 0x06 0x7f 0x0
[Channel1] sync_enabled Sync LED Deck A 0.5 1 0x91 0x05 0x7f 0x0
[Channel1] sync_leader Sync Leader LED Deck A (Shift) 0.5 1 0x93 0x05 0x7f 0x0
// Transport LEDs — Deck B
[Channel2] play_indicator Play LED Deck B 0.5 1 0x92 0x07 0x7f 0x0
[Channel2] cue_indicator Cue LED Deck B 0.5 1 0x92 0x06 0x7f 0x0
[Channel2] sync_enabled Sync LED Deck B 0.5 1 0x92 0x05 0x7f 0x0
[Channel2] sync_leader Sync Leader LED Deck B (Shift) 0.5 1 0x94 0x05 0x7f 0x0
// PFL LEDs
[Channel1] pfl PFL LED Deck A 0.5 1 0x91 0x0C 0x7f 0x0
[Channel2] pfl PFL LED Deck B 0.5 1 0x92 0x0C 0x7f 0x0
// Hotcue LEDs — Deck A (pads 1-4, normal and shift)
[Channel1] hotcue_1_status Hotcue 1 Deck A 0x96 0x00 0x7E 0.5
[Channel1] hotcue_2_status Hotcue 2 Deck A 0x96 0x01 0x7E 0.5
[Channel1] hotcue_3_status Hotcue 3 Deck A 0x96 0x02 0x7E 0.5
[Channel1] hotcue_4_status Hotcue 4 Deck A 0x96 0x03 0x7E 0.5
[Channel1] hotcue_1_status Hotcue 1 Deck A (Shift) 0x96 0x08 0x7E 0.5
[Channel1] hotcue_2_status Hotcue 2 Deck A (Shift) 0x96 0x09 0x7E 0.5
[Channel1] hotcue_3_status Hotcue 3 Deck A (Shift) 0x96 0x0A 0x7E 0.5
[Channel1] hotcue_4_status Hotcue 4 Deck A (Shift) 0x96 0x0B 0x7E 0.5
// Hotcue LEDs — Deck B (pads 1-4, normal and shift)
[Channel2] hotcue_1_status Hotcue 1 Deck B 0x97 0x00 0x7E 0.5
[Channel2] hotcue_2_status Hotcue 2 Deck B 0x97 0x01 0x7E 0.5
[Channel2] hotcue_3_status Hotcue 3 Deck B 0x97 0x02 0x7E 0.5
[Channel2] hotcue_4_status Hotcue 4 Deck B 0x97 0x03 0x7E 0.5
[Channel2] hotcue_1_status Hotcue 1 Deck B (Shift) 0x97 0x08 0x7E 0.5
[Channel2] hotcue_2_status Hotcue 2 Deck B (Shift) 0x97 0x09 0x7E 0.5
[Channel2] hotcue_3_status Hotcue 3 Deck B (Shift) 0x97 0x0A 0x7E 0.5
[Channel2] hotcue_4_status Hotcue 4 Deck B (Shift) 0x97 0x0B 0x7E 0.5
